"use client";

import { useState, Fragment } from "react";
import { useColorScheme } from "@mui/material/styles";
import Box from "@mui/material/Box";
import Button from "@mui/material/Button";
import Image from "next/image";
import { useTranslations } from "next-intl";

import Toast from "./Toast";

type Coin = "BTC" | "ETH";
type CoinStates = Coin | "off";
type CoinInfo = {
  id: Coin;
  fullname: string;
  address: string;
  qrImageSrc: string;
  qrImageSrcDark?: string;
};

const coins: CoinInfo[] = [
  {
    id: "BTC",
    fullname: "Bitcoin",
    address: "bc1qesms3zcc4um0m3mv94jrmtjnfd98jucm29d7yh",
    qrImageSrc:
      "data:image/png;base64,",
    qrImageSrcDark:
      "data:image/png;base64,",
  },
  {
    id: "ETH",
    fullname: "Ethereum",
    address: "0xCEee44eF4BD8A2B7af0917EC517449f32E448a65",
    qrImageSrc:
      "data:image/png;base64,",
    qrImageSrcDark:
      "data:image/png;base64,",
  },
];

export default function CryptoPayment() {
  const { mode, systemMode } = useColorScheme();
  const colorMode = mode === "system" ? systemMode : mode;
  const t = useTranslations("donation");
  const [showAddress, setShowAddress] = useState<CoinStates>("off");
  const [copiedAddress, setCopiedAddress] = useState<CoinStates>("off");

  const handleCloseToast = () => setCopiedAddress("off");
  const handleClickAddress = (coin: Coin, address: string) => () => {
    navigator.clipboard.writeText(address);
    setCopiedAddress(coin);
  };

  return (
    <>
      <p>{t("payment_title")}</p>
      <Box
        sx={{
          display: "flex",
          gap: 1,
          flexWrap: "wrap",
          justifyContent: "center",
          my: 2,
          marginTop: 0,
        }}
      >
        {coins.map((coin) => (
          <Button
            key={coin.id}
            color="primary"
            variant="outlined"
            onClick={() => {
              setShowAddress(showAddress === coin.id ? "off" : coin.id);
              setCopiedAddress("off");
            }}
            sx={{ borderRadius: "25px" }}
          >
            {coin.fullname} {coin.id}
          </Button>
        ))}
      </Box>
      {coins.map((coin) => (
        <Fragment key={coin.id}>
          <Box
            id={`${coin.id}-address`}
            sx={{ display: showAddress === coin.id ? "block" : "none", mb: 3 }}
          >
            <div>
              <b>{coin.fullname}</b>
            </div>
            <Box onClick={handleClickAddress(coin.id, coin.address)}>
              <a href={`${coin.fullname.toLowerCase()}:${coin.address}`}>
                <Image
                  alt={`${coin.id} Address`}
                  src={
                    colorMode === "dark" && coin.qrImageSrcDark
                      ? coin.qrImageSrcDark
                      : coin.qrImageSrc
                  }
                  width={160}
                  height={160}
                />
              </a>
            </Box>
            <Box
              sx={(theme) => ({
                display: "inline-block",
                border: 1,
                borderColor: theme.vars?.palette.divider,
                p: 0.5,
              })}
              onClick={handleClickAddress(coin.id, coin.address)}
            >
              {coin.address}
            </Box>
          </Box>
          <Toast
            message={t("copied", { coin: coin.id })}
            open={copiedAddress === coin.id}
            handleClose={handleCloseToast}
          />
        </Fragment>
      ))}
    </>
  );
}
